const INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\"/>\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"/>\n  <title>LumaDesign \u2014 Websites for Small Businesses</title>\n  <link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap\" rel=\"stylesheet\"/>\n  <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css\"/>\n  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n    :root {\n      --black: #09090b;\n      --white: #ffffff;\n      --gray-50: #fafafa;\n      --gray-100: #f4f4f5;\n      --gray-200: #e4e4e7;\n      --gray-300: #d4d4d8;\n      --gray-400: #a1a1aa;\n      --gray-500: #71717a;\n      --gray-700: #3f3f46;\n      --accent: #6366f1;\n      --accent-light: #eef2ff;\n      --accent-dark: #4f46e5;\n      --accent-glow: rgba(99,102,241,0.25);\n      --radius: 14px;\n    }\n\n    html { scroll-behavior: smooth; }\n    body {\n      font-family: 'Inter', sans-serif;\n      color: var(--black);\n      background: var(--white);\n      line-height: 1.6;\n      overflow-x: hidden;\n    }\n\n    /* \u2500\u2500 SCROLL ANIMATIONS \u2500\u2500 */\n    .reveal {\n      opacity: 0;\n      transform: translateY(32px);\n      transition: opacity 0.7s cubic-bezier(.16,1,.3,1), transform 0.7s cubic-bezier(.16,1,.3,1);\n    }\n    .reveal.from-left  { transform: translateX(-40px); }\n    .reveal.from-right { transform: translateX(40px); }\n    .reveal.scale-in   { transform: scale(0.92); }\n    .reveal.visible {\n      opacity: 1;\n      transform: translateY(0) translateX(0) scale(1);\n    }\n    .reveal-delay-1 { transition-delay: 0.08s; }\n    .reveal-delay-2 { transition-delay: 0.16s; }\n    .reveal-delay-3 { transition-delay: 0.24s; }\n    .reveal-delay-4 { transition-delay: 0.32s; }\n    .reveal-delay-5 { transition-delay: 0.40s; }\n\n    /* \u2500\u2500 HERO ENTRANCE \u2500\u2500 */\n    .hero-text > * {\n      opacity: 0;\n      transform: translateY(20px);\n      animation: heroEnter 0.7s cubic-bezier(.16,1,.3,1) forwards;\n    }\n    .hero-text > *:nth-child(1) { animation-delay: 0.1s; }\n    .hero-text > *:nth-child(2) { animation-delay: 0.22s; }\n    .hero-text > *:nth-child(3) { animation-delay: 0.34s; }\n    .hero-text > *:nth-child(4) { animation-delay: 0.46s; }\n    @keyframes heroEnter {\n      to { opacity: 1; transform: translateY(0); }\n    }\n    .hero-visual {\n      opacity: 0;\n      transform: translateY(24px) scale(0.97);\n      animation: heroEnter 0.9s cubic-bezier(.16,1,.3,1) 0.3s forwards;\n    }\n\n    /* \u2500\u2500 NAV \u2500\u2500 */\n    nav {\n      position: fixed; top: 0; left: 0; right: 0; z-index: 200;\n      display: flex; align-items: center; justify-content: space-between;\n      padding: 1rem 5%;\n      transition: background 0.3s, box-shadow 0.3s, padding 0.3s;\n    }\n    nav.scrolled {\n      background: rgba(255,255,255,0.92);\n      backdrop-filter: blur(16px);\n      box-shadow: 0 1px 0 var(--gray-200);\n      padding: 0.75rem 5%;\n    }\n\n    .logo {\n      font-size: 1.4rem; font-weight: 800; letter-spacing: -0.5px;\n      color: var(--black); text-decoration: none; display: flex; align-items: center; gap: 0.4rem;\n    }\n    .logo-dot { width: 8px; height: 8px; background: var(--accent); border-radius: 50%; display: inline-block; }\n    .logo span { color: var(--accent); }\n\n    .nav-links { display: flex; align-items: center; gap: 0.25rem; list-style: none; }\n    .nav-links a {\n      text-decoration: none; font-size: 0.875rem; font-weight: 500;\n      color: var(--gray-700); padding: 0.4rem 0.75rem; border-radius: 8px;\n      transition: background 0.15s, color 0.15s;\n    }\n    .nav-links a:hover { background: var(--gray-100); color: var(--black); }\n    .nav-cta {\n      background: var(--accent) !important; color: var(--white) !important;\n      padding: 0.5rem 1.1rem !important; border-radius: 9px !important;\n    }\n    .nav-cta:hover { background: var(--accent-dark) !important; }\n\n    /* Hamburger */\n    .hamburger {\n      display: none; flex-direction: column; gap: 5px; cursor: pointer;\n      background: none; border: none; padding: 4px;\n    }\n    .hamburger span {\n      display: block; width: 22px; height: 2px; background: var(--black);\n      border-radius: 2px; transition: transform 0.3s, opacity 0.3s;\n    }\n    .hamburger.open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }\n    .hamburger.open span:nth-child(2) { opacity: 0; }\n    .hamburger.open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }\n\n    .mobile-menu {\n      display: none; position: fixed; top: 0; left: 0; right: 0; bottom: 0;\n      background: var(--white); z-index: 190;\n      flex-direction: column; align-items: center; justify-content: center; gap: 1.5rem;\n    }\n    .mobile-menu.open { display: flex; }\n    .mobile-menu a {\n      font-size: 1.5rem; font-weight: 700; text-decoration: none; color: var(--black);\n      transition: color 0.2s;\n    }\n    .mobile-menu a:hover { color: var(--accent); }\n\n    /* \u2500\u2500 HERO \u2500\u2500 */\n    .hero {\n      min-height: 100vh;\n      display: flex; align-items: center;\n      padding: 8rem 5% 5rem;\n      position: relative; overflow: hidden;\n      background: var(--white);\n    }\n\n    /* Subtle animated gradient background */\n    .hero::before {\n      content: '';\n      position: absolute; inset: 0; z-index: 0;\n      background:\n        radial-gradient(ellipse 800px 500px at 70% 40%, rgba(99,102,241,0.08) 0%, transparent 70%),\n        radial-gradient(ellipse 600px 400px at 20% 80%, rgba(99,102,241,0.05) 0%, transparent 70%);\n      animation: heroPulse 8s ease-in-out infinite alternate;\n    }\n    @keyframes heroPulse {\n      from { opacity: 0.6; }\n      to { opacity: 1; }\n    }\n\n    .hero-inner {\n      max-width: 1120px; margin: 0 auto; position: relative; z-index: 1;\n      display: grid; grid-template-columns: 1fr 1fr; gap: 5rem; align-items: center;\n    }\n\n    .hero-badge {\n      display: inline-flex; align-items: center; gap: 0.5rem;\n      background: var(--accent-light); color: var(--accent);\n      font-size: 0.78rem; font-weight: 600;\n      padding: 0.35rem 0.85rem; border-radius: 100px;\n      margin-bottom: 1.5rem; border: 1px solid rgba(99,102,241,0.2);\n      letter-spacing: 0.04em; text-transform: uppercase;\n    }\n    .badge-dot { width: 6px; height: 6px; background: var(--accent); border-radius: 50%; animation: blink 1.8s ease-in-out infinite; }\n    @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.3} }\n\n    .hero h1 {\n      font-size: clamp(2.4rem, 4.5vw, 3.6rem);\n      font-weight: 800; line-height: 1.1; letter-spacing: -1.5px;\n      color: var(--black); margin-bottom: 1.25rem;\n    }\n    .gradient-text {\n      background: linear-gradient(135deg, var(--accent) 0%, #818cf8 100%);\n      -webkit-background-clip: text; -webkit-text-fill-color: transparent;\n      background-clip: text;\n    }\n\n    .hero p {\n      font-size: 1.1rem; color: var(--gray-500); max-width: 460px;\n      margin-bottom: 2.25rem; line-height: 1.75;\n    }\n\n    .hero-buttons { display: flex; gap: 0.875rem; flex-wrap: wrap; align-items: center; }\n\n    .btn-primary {\n      background: var(--accent); color: var(--white);\n      padding: 0.85rem 1.75rem; border-radius: 10px;\n      font-size: 0.95rem; font-weight: 600; text-decoration: none;\n      display: inline-flex; align-items: center; gap: 0.5rem;\n      transition: background 0.2s, transform 0.15s, box-shadow 0.2s;\n      box-shadow: 0 4px 14px var(--accent-glow);\n    }\n    .btn-primary:hover {\n      background: var(--accent-dark); transform: translateY(-2px);\n      box-shadow: 0 8px 24px var(--accent-glow);\n    }\n    .btn-secondary {\n      background: transparent; color: var(--black);\n      padding: 0.85rem 1.75rem; border-radius: 10px;\n      font-size: 0.95rem; font-weight: 600; text-decoration: none;\n      border: 1.5px solid var(--gray-200);\n      display: inline-flex; align-items: center; gap: 0.5rem;\n      transition: border-color 0.2s, color 0.2s, transform 0.15s;\n    }\n    .btn-secondary:hover { border-color: var(--accent); color: var(--accent); transform: translateY(-2px); }\n\n    /* Hero visual */\n    .hero-visual { position: relative; }\n\n    .browser-wrap {\n      position: relative;\n      filter: drop-shadow(0 30px 60px rgba(0,0,0,0.12));\n    }\n\n    .mock-browser {\n      background: var(--white); border-radius: 16px;\n      overflow: hidden; border: 1px solid var(--gray-200);\n    }\n    .mock-bar {\n      background: var(--gray-100); padding: 0.65rem 1rem;\n      display: flex; align-items: center; gap: 0.5rem;\n    }\n    .mock-dot { width: 10px; height: 10px; border-radius: 50%; }\n    .mock-dot:nth-child(1) { background: #ff5f57; }\n    .mock-dot:nth-child(2) { background: #ffbd2e; }\n    .mock-dot:nth-child(3) { background: #27c93f; }\n    .mock-url {\n      background: var(--white); border-radius: 6px;\n      font-size: 0.7rem; color: var(--gray-400); padding: 0.22rem 0.65rem;\n      flex: 1; font-family: monospace;\n    }\n\n    .mock-body { padding: 1.25rem; }\n    .mock-nav-bar {\n      display: flex; align-items: center; justify-content: space-between;\n      margin-bottom: 1rem; padding-bottom: 0.75rem;\n      border-bottom: 1px solid var(--gray-100);\n    }\n    .mock-logo-bar { height: 8px; width: 60px; background: var(--accent); border-radius: 4px; }\n    .mock-nav-links { display: flex; gap: 8px; }\n    .mock-nav-link { height: 6px; border-radius: 3px; background: var(--gray-200); }\n\n    .mock-hero-section { text-align: center; padding: 0.75rem 0 1rem; }\n    .mock-h { height: 10px; border-radius: 4px; background: var(--black); margin: 0 auto 6px; }\n    .mock-p { height: 7px; border-radius: 3px; background: var(--gray-200); margin: 0 auto 4px; }\n    .mock-btn-row { display: flex; justify-content: center; gap: 6px; margin-top: 10px; }\n    .mock-btn { height: 22px; border-radius: 5px; }\n\n    .mock-cards { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 8px; margin-top: 0.75rem; }\n    .mock-card-item {\n      border-radius: 8px; padding: 8px;\n      background: var(--gray-50); border: 1px solid var(--gray-100);\n    }\n    .mc-icon { width: 18px; height: 18px; border-radius: 5px; background: var(--accent-light); margin-bottom: 6px; }\n    .mc-line { height: 5px; border-radius: 3px; background: var(--gray-200); margin-bottom: 3px; }\n    .mc-line.short { width: 60%; }\n\n    /* Floating badges on hero visual */\n    .float-badge {\n      position: absolute; background: var(--white); border-radius: 12px;\n      padding: 0.6rem 0.9rem; display: flex; align-items: center; gap: 0.5rem;\n      box-shadow: 0 8px 24px rgba(0,0,0,0.1); border: 1px solid var(--gray-100);\n      font-size: 0.78rem; font-weight: 600; animation: floatY 4s ease-in-out infinite;\n    }\n    .float-badge.b1 { bottom: -16px; left: -20px; animation-delay: 0s; }\n    .float-badge.b2 { top: -16px; right: -16px; animation-delay: 2s; }\n    @keyframes floatY { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-6px)} }\n\n    .fb-icon { width: 28px; height: 28px; border-radius: 8px; background: var(--accent-light); display: flex; align-items: center; justify-content: center; color: var(--accent); font-size: 0.8rem; }\n    .fb-label { color: var(--gray-500); font-weight: 400; }\n    .fb-val { color: var(--black); }\n\n    /* \u2500\u2500 SOCIAL PROOF STRIP \u2500\u2500 */\n    .proof-strip {\n      padding: 1.5rem 5%; background: var(--gray-50);\n      border-top: 1px solid var(--gray-100); border-bottom: 1px solid var(--gray-100);\n    }\n    .proof-inner {\n      max-width: 1120px; margin: 0 auto;\n      display: flex; align-items: center; gap: 2rem; flex-wrap: wrap;\n      justify-content: center;\n    }\n    .proof-label { font-size: 0.8rem; color: var(--gray-400); font-weight: 500; white-space: nowrap; }\n    .proof-divider { width: 1px; height: 20px; background: var(--gray-200); }\n    .proof-stat { display: flex; align-items: center; gap: 0.4rem; }\n    .proof-stat-num { font-size: 1rem; font-weight: 700; color: var(--black); }\n    .proof-stat-text { font-size: 0.82rem; color: var(--gray-500); }\n\n    /* \u2500\u2500 SECTION BASE \u2500\u2500 */\n    section { padding: 6rem 5%; }\n    .section-inner { max-width: 1120px; margin: 0 auto; }\n    .section-header { margin-bottom: 3.5rem; }\n    .section-tag {\n      display: inline-flex; align-items: center; gap: 0.4rem;\n      font-size: 0.75rem; font-weight: 700; text-transform: uppercase;\n      letter-spacing: 0.1em; color: var(--accent); margin-bottom: 0.75rem;\n    }\n    .section-tag::before { content: ''; width: 16px; height: 2px; background: var(--accent); border-radius: 1px; }\n    .section-title {\n      font-size: clamp(1.8rem, 3vw, 2.6rem); font-weight: 800;\n      letter-spacing: -0.75px; color: var(--black); line-height: 1.15;\n      margin-bottom: 0.875rem;\n    }\n    .section-sub { font-size: 1.05rem; color: var(--gray-500); max-width: 540px; line-height: 1.75; }\n\n    /* \u2500\u2500 PROBLEM \u2500\u2500 */\n    .problem { background: var(--black); }\n    .problem .section-title { color: var(--white); }\n    .problem .section-sub { color: var(--gray-400); }\n    .problem .section-tag { color: #a5b4fc; }\n    .problem .section-tag::before { background: #a5b4fc; }\n\n    .problem-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.5rem; }\n    .problem-card {\n      border: 1px solid #27272a; border-radius: var(--radius); padding: 1.75rem;\n      cursor: default; position: relative; overflow: hidden;\n    }\n    /* Spotlight glow follows mouse via JS */\n    .problem-card::before {\n      content: '';\n      position: absolute;\n      width: 200px; height: 200px;\n      background: radial-gradient(circle, rgba(99,102,241,0.12) 0%, transparent 70%);\n      border-radius: 50%;\n      transform: translate(-50%, -50%);\n      left: var(--mx, -999px); top: var(--my, -999px);\n      pointer-events: none; transition: opacity 0.3s;\n      opacity: 0;\n    }\n    .problem-card:hover::before { opacity: 1; }\n    .problem-icon {\n      width: 52px; height: 52px; background: #18181b; border-radius: 12px;\n      display: flex; align-items: center; justify-content: center;\n      margin-bottom: 1.25rem; font-size: 1.25rem; color: #a5b4fc;\n      border: 1px solid #27272a;\n    }\n    .problem-card h3 { color: var(--white); font-size: 1rem; font-weight: 600; margin-bottom: 0.5rem; }\n    .problem-card p { color: #71717a; font-size: 0.875rem; line-height: 1.65; }\n\n    /* \u2500\u2500 SERVICES \u2500\u2500 */\n    .services { background: var(--gray-50); }\n    .services-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; }\n    .service-card {\n      background: var(--white); border: 1px solid var(--gray-200);\n      border-radius: var(--radius); padding: 1.75rem; cursor: default;\n    }\n    .service-icon {\n      width: 46px; height: 46px; background: var(--accent-light); border-radius: 12px;\n      display: flex; align-items: center; justify-content: center;\n      font-size: 1.1rem; color: var(--accent); margin-bottom: 1.1rem;\n    }\n    /* Icon pops in when card becomes visible */\n    .service-card.visible .service-icon {\n      animation: iconPop 0.5s cubic-bezier(.34,1.56,.64,1) both;\n    }\n    @keyframes iconPop {\n      from { transform: scale(0.5); opacity: 0; }\n      to   { transform: scale(1);   opacity: 1; }\n    }\n    .service-card h3 { font-size: 0.975rem; font-weight: 600; margin-bottom: 0.45rem; }\n    .service-card p { font-size: 0.875rem; color: var(--gray-500); line-height: 1.65; }\n\n    /* \u2500\u2500 BEFORE/AFTER \u2500\u2500 */\n    .ba-section { background: var(--white); }\n    .ba-wrapper {\n      display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; margin-top: 3.5rem;\n      align-items: start;\n    }\n    .ba-card {\n      border-radius: var(--radius); overflow: hidden;\n      border: 1px solid var(--gray-200);\n      box-shadow: 0 4px 20px rgba(0,0,0,0.06);\n    }\n    .ba-label {\n      padding: 0.6rem 1rem; font-size: 0.78rem; font-weight: 700;\n      text-transform: uppercase; letter-spacing: 0.08em; display: flex; align-items: center; gap: 0.4rem;\n    }\n    .ba-label.before { background: #fef2f2; color: #ef4444; }\n    .ba-label.after  { background: #f0fdf4; color: #16a34a; }\n    .ba-browser { background: var(--white); padding: 1rem; }\n\n    /* Old site mock */\n    .old-hero { background: #c5c5c5; height: 80px; margin-bottom: 8px; border-radius: 4px; display: flex; align-items: center; justify-content: center; }\n    .old-hero-text { font-size: 0.7rem; color: #555; font-weight: 700; font-family: 'Times New Roman', serif; }\n    .old-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; }\n    .old-box { background: #e8e8e8; border: 2px solid #aaa; border-radius: 2px; padding: 6px; }\n    .old-title-bar { height: 6px; background: #888; border-radius: 2px; margin-bottom: 4px; width: 70%; }\n    .old-text { height: 4px; background: #bbb; border-radius: 2px; margin-bottom: 3px; }\n    .old-btn { background: #336699; color: white; font-size: 0.55rem; padding: 2px 6px; border-radius: 2px; display: inline-block; margin-top: 4px; font-family: Arial, sans-serif; }\n\n    /* New site mock */\n    .new-hero { background: linear-gradient(135deg, #eef2ff, #f8f9ff); height: 80px; margin-bottom: 8px; border-radius: 8px; display: flex; align-items: center; padding: 0 12px; }\n    .new-hero-content { }\n    .new-h { height: 9px; background: var(--accent); border-radius: 4px; width: 100px; margin-bottom: 4px; }\n    .new-p { height: 6px; background: #c7d2fe; border-radius: 3px; width: 130px; }\n    .new-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 6px; }\n    .new-box { background: var(--white); border: 1px solid var(--gray-100); border-radius: 8px; padding: 8px; }\n    .new-icon-sq { width: 16px; height: 16px; background: var(--accent-light); border-radius: 4px; margin-bottom: 4px; }\n    .new-title { height: 6px; background: var(--black); border-radius: 3px; width: 70%; margin-bottom: 3px; }\n    .new-text { height: 4px; background: var(--gray-200); border-radius: 2px; margin-bottom: 2px; }\n\n    /* \u2500\u2500 PORTFOLIO \u2500\u2500 */\n    .portfolio { background: var(--gray-50); }\n    .portfolio-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.5rem; margin-top: 3.5rem; }\n    .portfolio-card {\n      background: var(--white); border: 1px solid var(--gray-200); border-radius: var(--radius);\n      overflow: hidden; transition: transform 0.25s, box-shadow 0.25s;\n      cursor: pointer;\n    }\n    .portfolio-card:hover { transform: translateY(-4px); box-shadow: 0 20px 50px rgba(0,0,0,0.1); }\n\n    .portfolio-thumb {\n      height: 170px; padding: 1.25rem; display: flex; flex-direction: column;\n      justify-content: flex-start; position: relative; overflow: hidden;\n    }\n    .pt-1 { background: linear-gradient(135deg, #fef3c7, #fde68a); }\n    .pt-2 { background: linear-gradient(135deg, #d1fae5, #a7f3d0); }\n    .pt-3 { background: linear-gradient(135deg, #ede9fe, #ddd6fe); }\n    .pt-4 { background: linear-gradient(135deg, #fee2e2, #fecaca); }\n    .pt-5 { background: linear-gradient(135deg, #dbeafe, #bfdbfe); }\n    .pt-6 { background: linear-gradient(135deg, #fce7f3, #fbcfe8); }\n\n    .pt-browser {\n      background: rgba(255,255,255,0.9); border-radius: 8px;\n      overflow: hidden; border: 1px solid rgba(255,255,255,0.6);\n      box-shadow: 0 4px 16px rgba(0,0,0,0.08);\n    }\n    .pt-bar { background: rgba(0,0,0,0.06); padding: 5px 8px; display: flex; gap: 4px; align-items: center; }\n    .pt-dot { width: 6px; height: 6px; border-radius: 50%; background: rgba(0,0,0,0.15); }\n    .pt-content { padding: 8px; }\n    .pt-hl { height: 7px; border-radius: 3px; background: rgba(0,0,0,0.15); margin-bottom: 4px; }\n    .pt-pl { height: 5px; border-radius: 2px; background: rgba(0,0,0,0.08); margin-bottom: 3px; }\n    .pt-pl.s { width: 60%; }\n    .pt-mini-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 4px; margin-top: 6px; }\n    .pt-mini-card { height: 20px; border-radius: 4px; background: rgba(0,0,0,0.07); }\n\n    .portfolio-info { padding: 1.1rem 1.25rem; }\n    .portfolio-industry { font-size: 0.72rem; font-weight: 600; color: var(--accent); text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 0.3rem; }\n    .portfolio-name { font-size: 0.95rem; font-weight: 600; color: var(--black); margin-bottom: 0.25rem; }\n    .portfolio-desc { font-size: 0.8rem; color: var(--gray-400); }\n\n    /* \u2500\u2500 PROCESS \u2500\u2500 */\n    .process-section { background: var(--white); }\n    .process-steps {\n      display: grid; grid-template-columns: repeat(4, 1fr); gap: 1.5rem;\n      position: relative; margin-top: 3.5rem;\n    }\n    .process-line {\n      position: absolute; top: 23px; left: calc(12.5% + 24px); right: calc(12.5% + 24px);\n      height: 1px; background: var(--gray-200); z-index: 0;\n    }\n    .process-line-fill {\n      height: 100%; background: linear-gradient(to right, var(--accent), #818cf8);\n      width: 0%; transition: width 1.5s cubic-bezier(.16,1,.3,1);\n    }\n    .process-line-fill.animate { width: 100%; }\n\n    .step { text-align: center; position: relative; z-index: 1; }\n    .step-num {\n      width: 46px; height: 46px; background: var(--white); border: 2px solid var(--gray-200);\n      border-radius: 50%; display: flex; align-items: center; justify-content: center;\n      font-weight: 700; font-size: 0.875rem; margin: 0 auto 1rem;\n      color: var(--gray-400); transition: border-color 0.3s, color 0.3s, background 0.3s;\n    }\n    .step.active .step-num {\n      border-color: var(--accent); color: var(--accent); background: var(--accent-light);\n    }\n    .step h3 { font-size: 0.9rem; font-weight: 600; margin-bottom: 0.4rem; color: var(--black); }\n    .step p { font-size: 0.82rem; color: var(--gray-500); line-height: 1.55; }\n\n    /* \u2500\u2500 PRICING \u2500\u2500 */\n    .pricing-section { background: var(--gray-50); }\n    .pricing-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.5rem; }\n    .price-card {\n      background: var(--white); border: 1.5px solid var(--gray-200);\n      border-radius: 18px; padding: 2rem; position: relative;\n      transition: box-shadow 0.2s, transform 0.2s;\n    }\n    .price-card:hover { transform: translateY(-3px); box-shadow: 0 12px 40px rgba(0,0,0,0.08); }\n    .price-card.featured {\n      border-color: var(--accent);\n      box-shadow: 0 8px 32px rgba(99,102,241,0.15);\n    }\n    .price-card.featured:hover { box-shadow: 0 16px 48px rgba(99,102,241,0.2); }\n    .popular-badge {\n      position: absolute; top: -13px; left: 50%; transform: translateX(-50%);\n      background: var(--accent); color: var(--white);\n      font-size: 0.7rem; font-weight: 700; padding: 0.28rem 0.85rem;\n      border-radius: 100px; letter-spacing: 0.05em; text-transform: uppercase;\n      white-space: nowrap;\n    }\n    .price-name { font-size: 0.78rem; font-weight: 700; color: var(--gray-400); text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 0.75rem; }\n    .price-amount { font-size: 2.75rem; font-weight: 800; color: var(--black); line-height: 1; margin-bottom: 0.3rem; letter-spacing: -1px; }\n    .price-amount sup { font-size: 1.2rem; font-weight: 700; vertical-align: super; }\n    .price-desc { font-size: 0.83rem; color: var(--gray-400); margin-bottom: 1.5rem; padding-bottom: 1.5rem; border-bottom: 1px solid var(--gray-100); }\n    .price-features { list-style: none; margin-bottom: 1.75rem; display: flex; flex-direction: column; gap: 0.6rem; }\n    .price-features li {\n      font-size: 0.86rem; color: var(--gray-700);\n      display: flex; align-items: center; gap: 0.6rem;\n    }\n    .check-icon { width: 18px; height: 18px; background: #dcfce7; border-radius: 50%; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }\n    .check-icon i { font-size: 0.55rem; color: #16a34a; }\n    .price-card.featured .check-icon { background: var(--accent-light); }\n    .price-card.featured .check-icon i { color: var(--accent); }\n\n    /* \u2500\u2500 TESTIMONIALS \u2500\u2500 */\n    .testimonials { background: var(--white); }\n    .testimonials-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; }\n    .testimonial {\n      background: var(--gray-50); border: 1px solid var(--gray-100);\n      border-radius: var(--radius); padding: 1.75rem; cursor: default;\n    }\n    .stars { display: flex; gap: 2px; margin-bottom: 1rem; color: #f59e0b; font-size: 0.9rem; }\n    .stars i { opacity: 0; }\n    .testimonial.visible .stars i:nth-child(1) { animation: starIn 0.3s ease 0.05s forwards; }\n    .testimonial.visible .stars i:nth-child(2) { animation: starIn 0.3s ease 0.15s forwards; }\n    .testimonial.visible .stars i:nth-child(3) { animation: starIn 0.3s ease 0.25s forwards; }\n    .testimonial.visible .stars i:nth-child(4) { animation: starIn 0.3s ease 0.35s forwards; }\n    .testimonial.visible .stars i:nth-child(5) { animation: starIn 0.3s ease 0.45s forwards; }\n    @keyframes starIn {\n      from { opacity: 0; transform: scale(0) rotate(-30deg); }\n      to   { opacity: 1; transform: scale(1) rotate(0deg); }\n    }\n    .testimonial blockquote { font-size: 0.9rem; color: var(--gray-700); line-height: 1.75; margin-bottom: 1.25rem; }\n    .testimonial-author { display: flex; align-items: center; gap: 0.75rem; }\n    .avatar {\n      width: 38px; height: 38px; border-radius: 50%;\n      background: linear-gradient(135deg, var(--accent), #818cf8);\n      display: flex; align-items: center; justify-content: center;\n      font-weight: 700; font-size: 0.82rem; color: var(--white);\n      flex-shrink: 0;\n    }\n    .author-name { font-size: 0.875rem; font-weight: 600; }\n    .author-biz { font-size: 0.775rem; color: var(--gray-400); }\n\n    /* \u2500\u2500 FAQ \u2500\u2500 */\n    .faq-section { background: var(--gray-50); }\n    .faq-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1px; background: var(--gray-200); border-radius: var(--radius); overflow: hidden; margin-top: 3rem; }\n    .faq-item { background: var(--white); padding: 1.5rem; cursor: pointer; }\n    .faq-item:hover { background: var(--gray-50); }\n    .faq-q {\n      display: flex; justify-content: space-between; align-items: flex-start;\n      gap: 1rem; font-size: 0.9rem; font-weight: 600; color: var(--black);\n    }\n    .faq-icon { color: var(--accent); font-size: 0.8rem; flex-shrink: 0; margin-top: 2px; transition: transform 0.2s; }\n    .faq-a { font-size: 0.85rem; color: var(--gray-500); line-height: 1.65; margin-top: 0.75rem; display: none; }\n    .faq-item.open .faq-a { display: block; }\n    .faq-item.open .faq-icon { transform: rotate(45deg); }\n\n    /* \u2500\u2500 CTA \u2500\u2500 */\n    .cta-section {\n      padding: 6rem 5%;\n      background: linear-gradient(135deg, #4f46e5 0%, #6366f1 50%, #818cf8 100%);\n      position: relative; overflow: hidden;\n    }\n    .cta-section::before {\n      content: ''; position: absolute; inset: 0;\n      background: url(\"data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.04'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E\");\n    }\n    .cta-inner { max-width: 640px; margin: 0 auto; text-align: center; position: relative; z-index: 1; }\n    .cta-section h2 { font-size: clamp(1.9rem, 3.5vw, 2.75rem); color: var(--white); font-weight: 800; margin-bottom: 1rem; letter-spacing: -0.5px; }\n    .cta-section p { color: rgba(255,255,255,0.75); font-size: 1.05rem; margin-bottom: 2rem; line-height: 1.7; }\n    .btn-white {\n      background: var(--white); color: var(--accent);\n      padding: 0.9rem 2rem; border-radius: 10px; font-size: 1rem; font-weight: 700;\n      text-decoration: none; display: inline-flex; align-items: center; gap: 0.5rem;\n      transition: transform 0.15s, box-shadow 0.15s;\n    }\n    .btn-white:hover { transform: translateY(-2px); box-shadow: 0 12px 32px rgba(0,0,0,0.2); }\n\n    /* \u2500\u2500 CONTACT \u2500\u2500 */\n    .contact-section { background: var(--white); }\n    .contact-grid { display: grid; grid-template-columns: 1fr 1.3fr; gap: 5rem; align-items: start; margin-top: 3.5rem; }\n    .contact-info h3 { font-size: 1.3rem; font-weight: 700; margin-bottom: 0.6rem; }\n    .contact-info > p { color: var(--gray-500); font-size: 0.92rem; margin-bottom: 2rem; line-height: 1.7; }\n    .contact-item { display: flex; align-items: center; gap: 0.875rem; margin-bottom: 1.1rem; }\n    .ci-icon {\n      width: 38px; height: 38px; background: var(--accent-light);\n      border-radius: 10px; display: flex; align-items: center; justify-content: center;\n      color: var(--accent); font-size: 0.875rem; flex-shrink: 0;\n    }\n    .ci-label { font-size: 0.72rem; color: var(--gray-400); font-weight: 500; }\n    .ci-val { font-size: 0.875rem; font-weight: 600; color: var(--black); }\n\n    form { display: flex; flex-direction: column; gap: 0.875rem; }\n    .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 0.875rem; }\n    label { font-size: 0.78rem; font-weight: 600; color: var(--gray-700); margin-bottom: 0.3rem; display: block; }\n    input, textarea, select {\n      width: 100%; padding: 0.7rem 0.9rem;\n      border: 1.5px solid var(--gray-200); border-radius: 9px;\n      font-family: inherit; font-size: 0.875rem; color: var(--black);\n      background: var(--white); outline: none; transition: border-color 0.2s, box-shadow 0.2s;\n    }\n    input:focus, textarea:focus, select:focus {\n      border-color: var(--accent);\n      box-shadow: 0 0 0 3px rgba(99,102,241,0.12);\n    }\n    textarea { resize: vertical; min-height: 110px; }\n    .form-submit {\n      background: var(--accent); color: var(--white); border: none;\n      padding: 0.875rem; border-radius: 9px; font-family: inherit;\n      font-size: 0.95rem; font-weight: 600; cursor: pointer;\n      transition: background 0.2s, transform 0.15s, box-shadow 0.2s;\n      box-shadow: 0 4px 14px var(--accent-glow);\n      display: flex; align-items: center; justify-content: center; gap: 0.5rem;\n    }\n    .form-submit:hover { background: var(--accent-dark); transform: translateY(-1px); box-shadow: 0 8px 24px var(--accent-glow); }\n\n    /* \u2500\u2500 FOOTER \u2500\u2500 */\n    footer {\n      background: var(--black); padding: 3.5rem 5% 2rem;\n    }\n    .footer-top {\n      display: grid; grid-template-columns: 2fr 1fr 1fr 1fr;\n      gap: 3rem; padding-bottom: 2.5rem;\n      border-bottom: 1px solid #18181b; margin-bottom: 2rem;\n    }\n    .footer-logo { font-size: 1.3rem; font-weight: 800; color: var(--white); margin-bottom: 0.75rem; }\n    .footer-logo span { color: var(--accent); }\n    .footer-desc { font-size: 0.85rem; color: #71717a; line-height: 1.65; max-width: 240px; margin-bottom: 1.25rem; }\n    .footer-socials { display: flex; gap: 0.6rem; }\n    .social-btn {\n      width: 34px; height: 34px; background: #18181b; border-radius: 8px;\n      display: flex; align-items: center; justify-content: center;\n      color: #71717a; font-size: 0.85rem; text-decoration: none;\n      transition: background 0.2s, color 0.2s;\n    }\n    .social-btn:hover { background: var(--accent); color: var(--white); }\n    .footer-col h4 { font-size: 0.78rem; font-weight: 700; color: var(--white); text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 1rem; }\n    .footer-col ul { list-style: none; display: flex; flex-direction: column; gap: 0.6rem; }\n    .footer-col ul a { font-size: 0.85rem; color: #71717a; text-decoration: none; transition: color 0.2s; }\n    .footer-col ul a:hover { color: var(--white); }\n    .footer-bottom { display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 0.5rem; }\n    .footer-bottom p { font-size: 0.8rem; color: #52525b; }\n    .footer-bottom a { color: #52525b; text-decoration: none; font-size: 0.8rem; transition: color 0.2s; }\n    .footer-bottom a:hover { color: var(--white); }\n\n    /* \u2500\u2500 BACK TO TOP \u2500\u2500 */\n    .back-top {\n      position: fixed; bottom: 2rem; right: 2rem; z-index: 100;\n      width: 42px; height: 42px; background: var(--accent); color: var(--white);\n      border-radius: 12px; display: flex; align-items: center; justify-content: center;\n      font-size: 0.85rem; cursor: pointer; border: none;\n      opacity: 0; pointer-events: none; transition: opacity 0.3s, transform 0.3s;\n      box-shadow: 0 4px 14px var(--accent-glow);\n    }\n    .back-top.visible { opacity: 1; pointer-events: all; }\n    .back-top:hover { transform: translateY(-2px); }\n\n    /* \u2500\u2500 RESPONSIVE \u2500\u2500 */\n\n    /* TV / large monitors (1920px+) */\n    @media (min-width: 1920px) {\n      .section-inner, .hero-inner, .proof-inner, .cta-inner, .contact-grid { max-width: 1400px; }\n      .hero h1 { font-size: 4.2rem; }\n      .section-title { font-size: 3rem; }\n      body { font-size: 18px; }\n    }\n\n    /* Large desktop (1280\u20131919px) \u2014 default styles handle this fine */\n\n    /* Laptop / small desktop (960\u20131279px) */\n    @media (max-width: 1279px) {\n      .hero-inner { gap: 3rem; }\n      .hero h1 { font-size: clamp(2rem, 3.5vw, 3rem); }\n      .footer-top { grid-template-columns: 1.5fr 1fr 1fr 1fr; gap: 2rem; }\n    }\n\n    /* Tablet / iPad (768\u2013959px) */\n    @media (max-width: 959px) {\n      .hero-inner, .contact-grid { grid-template-columns: 1fr; }\n      .hero-visual { display: none; }\n      .hero { padding: 7rem 5% 4rem; min-height: auto; }\n      .hero h1 { font-size: clamp(2rem, 5vw, 2.8rem); }\n      .problem-grid, .services-grid, .testimonials-grid { grid-template-columns: 1fr 1fr; }\n      .process-steps { grid-template-columns: 1fr 1fr; gap: 2rem; }\n      .process-line { display: none; }\n      .faq-grid { grid-template-columns: 1fr; }\n      .footer-top { grid-template-columns: 1fr 1fr; gap: 2rem; }\n      section { padding: 5rem 5%; }\n      /* Why section stacks on tablet */\n      [style*=\"grid-template-columns:1fr 1fr\"] { grid-template-columns: 1fr !important; }\n    }\n\n    /* Large phone / small tablet (640\u2013767px) */\n    @media (max-width: 767px) {\n      .nav-links { display: none; }\n      .hamburger { display: flex; }\n      .problem-grid, .services-grid, .testimonials-grid { grid-template-columns: 1fr 1fr; }\n      .process-steps { grid-template-columns: 1fr 1fr; }\n      .form-row { grid-template-columns: 1fr; }\n      .footer-top { grid-template-columns: 1fr 1fr; }\n      .proof-inner { gap: 1rem; }\n    }\n\n    /* Mobile / iPhone (max 639px) */\n    @media (max-width: 639px) {\n      .problem-grid, .services-grid, .testimonials-grid, .process-steps { grid-template-columns: 1fr; }\n      .footer-top { grid-template-columns: 1fr; }\n      .proof-divider { display: none; }\n      .hero-buttons { flex-direction: column; align-items: flex-start; }\n      .hero-buttons a { width: 100%; justify-content: center; }\n      section { padding: 4rem 5%; }\n      .section-title { font-size: 1.75rem; }\n      .float-badge { display: none; }\n      .hero { padding: 6rem 5% 3rem; }\n      .cta-section { padding: 4rem 5%; }\n      nav { padding: 1rem 5%; }\n      .back-top { bottom: 1.25rem; right: 1.25rem; }\n    }\n\n    /* Small phones (max 390px \u2014 iPhone SE, older Androids) */\n    @media (max-width: 390px) {\n      .hero h1 { font-size: 1.75rem; letter-spacing: -0.5px; }\n      .hero p { font-size: 0.95rem; }\n      .logo { font-size: 1.2rem; }\n      .proof-inner { flex-direction: column; align-items: flex-start; gap: 0.75rem; }\n      .proof-divider { display: none; }\n    }\n  </style>\n</head>\n<body>\n\n<!-- MOBILE MENU -->\n<div class=\"mobile-menu\" id=\"mobileMenu\">\n  <a href=\"#services\" onclick=\"closeMobile()\">Services</a>\n  <a href=\"#pricing\" onclick=\"closeMobile()\">Pricing</a>\n  <a href=\"contact.html\" onclick=\"closeMobile()\" style=\"color:var(--accent)\">Get Started \u2192</a>\n</div>\n\n<!-- NAV -->\n<nav id=\"mainNav\">\n  <a href=\"#\" class=\"logo\"><div class=\"logo-dot\"></div>luma<span>design</span></a>\n  <ul class=\"nav-links\">\n    <li><a href=\"#services\">Services</a></li>\n    <li><a href=\"#process\">How It Works</a></li>\n    <li><a href=\"#faq\">FAQ</a></li>\n    <li><a href=\"contact.html\" class=\"nav-cta\">Get Started</a></li>\n  </ul>\n  <button class=\"hamburger\" id=\"hamburger\" onclick=\"toggleMobile()\" aria-label=\"Menu\">\n    <span></span><span></span><span></span>\n  </button>\n</nav>\n\n<!-- HERO -->\n<section class=\"hero\">\n  <div class=\"hero-inner\">\n    <div class=\"hero-text\">\n      <div class=\"hero-badge\"><div class=\"badge-dot\"></div> Custom Web Design for Small Business</div>\n      <h1>Your business deserves a website that <span class=\"gradient-text\">actually works</span></h1>\n      <p>We build clean, modern, custom websites for small businesses \u2014 whether you're starting from scratch or finally ready to leave the old one behind.</p>\n      <div class=\"hero-buttons\">\n        <a href=\"contact.html\" class=\"btn-primary\">Get a Free Quote <i class=\"fa-solid fa-arrow-right\"></i></a>\n        <a href=\"#process\" class=\"btn-secondary\"><i class=\"fa-solid fa-arrow-down\"></i> How It Works</a>\n      </div>\n    </div>\n    <div class=\"hero-visual\">\n      <div class=\"browser-wrap\">\n        <div class=\"mock-browser\">\n          <div class=\"mock-bar\">\n            <div class=\"mock-dot\"></div><div class=\"mock-dot\"></div><div class=\"mock-dot\"></div>\n            <div class=\"mock-url\">www.yourbusiness.com</div>\n          </div>\n          <div class=\"mock-body\">\n            <div class=\"mock-nav-bar\">\n              <div class=\"mock-logo-bar\"></div>\n              <div class=\"mock-nav-links\">\n                <div class=\"mock-nav-link\" style=\"width:28px\"></div>\n                <div class=\"mock-nav-link\" style=\"width:36px\"></div>\n                <div class=\"mock-nav-link\" style=\"width:24px\"></div>\n                <div class=\"mock-nav-link\" style=\"width:50px;background:var(--accent);border-radius:3px\"></div>\n              </div>\n            </div>\n            <div class=\"mock-hero-section\">\n              <div class=\"mock-h\" style=\"width:75%\"></div>\n              <div class=\"mock-p\" style=\"width:65%\"></div>\n              <div class=\"mock-p\" style=\"width:50%\"></div>\n              <div class=\"mock-btn-row\">\n                <div class=\"mock-btn\" style=\"width:80px;background:var(--accent)\"></div>\n                <div class=\"mock-btn\" style=\"width:80px;background:var(--gray-200)\"></div>\n              </div>\n            </div>\n            <div class=\"mock-cards\">\n              <div class=\"mock-card-item\"><div class=\"mc-icon\"></div><div class=\"mc-line\"></div><div class=\"mc-line short\"></div></div>\n              <div class=\"mock-card-item\"><div class=\"mc-icon\" style=\"background:#d1fae5\"></div><div class=\"mc-line\"></div><div class=\"mc-line short\"></div></div>\n              <div class=\"mock-card-item\"><div class=\"mc-icon\" style=\"background:#fef3c7\"></div><div class=\"mc-line\"></div><div class=\"mc-line short\"></div></div>\n            </div>\n          </div>\n        </div>\n        <div class=\"float-badge b1\">\n          <div class=\"fb-icon\"><i class=\"fa-solid fa-bolt\"></i></div>\n          <div><div class=\"fb-val\">3\u00d7 more leads</div><div class=\"fb-label\">after launch</div></div>\n        </div>\n        <div class=\"float-badge b2\">\n          <div class=\"fb-icon\"><i class=\"fa-solid fa-clock\"></i></div>\n          <div><div class=\"fb-val\">7 days avg</div><div class=\"fb-label\">delivery time</div></div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- SOCIAL PROOF STRIP -->\n<div class=\"proof-strip\">\n  <div class=\"proof-inner\">\n    <span class=\"proof-label\">Trusted by small businesses across industries</span>\n    <div class=\"proof-divider\"></div>\n    <div class=\"proof-stat\"><span class=\"proof-stat-num count-up\" data-target=\"50\" data-suffix=\"+\">50+</span><span class=\"proof-stat-text\">sites launched</span></div>\n    <div class=\"proof-divider\"></div>\n    <div class=\"proof-stat\"><span class=\"proof-stat-num count-up\" data-target=\"4.9\" data-suffix=\"\u2605\" data-decimals=\"1\">4.9\u2605</span><span class=\"proof-stat-text\">avg rating</span></div>\n    <div class=\"proof-divider\"></div>\n    <div class=\"proof-stat\"><span class=\"proof-stat-num count-up\" data-target=\"100\" data-suffix=\"%\">100%</span><span class=\"proof-stat-text\">custom-built</span></div>\n    <div class=\"proof-divider\"></div>\n    <div class=\"proof-stat\"><span class=\"proof-stat-num count-up\" data-target=\"7\" data-prefix=\"&lt;\" data-suffix=\" days\">&#60;7 days</span><span class=\"proof-stat-text\">from kickoff to launch</span></div>\n  </div>\n</div>\n\n<!-- PROBLEM -->\n<section class=\"problem\">\n  <div class=\"section-inner\">\n    <div class=\"section-header\">\n      <div class=\"section-tag\">The Problem</div>\n      <h2 class=\"section-title\" style=\"color:white\">A bad website is costing you<br>customers every day</h2>\n      <p class=\"section-sub\">Most small businesses are losing potential clients without even knowing it.</p>\n    </div>\n    <div class=\"problem-grid\">\n      <div class=\"problem-card reveal\">\n        <div class=\"problem-icon\"><i class=\"fa-solid fa-ban\"></i></div>\n        <h3>No website at all</h3>\n        <p>Over 70% of consumers check a business online before visiting. If you're not there, they go straight to a competitor who is.</p>\n      </div>\n      <div class=\"problem-card reveal reveal-delay-2\">\n        <div class=\"problem-icon\"><i class=\"fa-solid fa-clock-rotate-left\"></i></div>\n        <h3>Outdated design</h3>\n        <p>An old-looking site signals an old-looking business. Visitors make a judgment about your credibility in under 3 seconds.</p>\n      </div>\n      <div class=\"problem-card reveal reveal-delay-3\">\n        <div class=\"problem-icon\"><i class=\"fa-solid fa-mobile-screen-button\"></i></div>\n        <h3>Not mobile-friendly</h3>\n        <p>More than 60% of web traffic is on phones. A site that doesn't work on mobile loses more than half your potential visitors.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n\n<!-- SERVICES -->\n<section class=\"services\" id=\"services\">\n  <div class=\"section-inner\">\n    <div class=\"section-header reveal\">\n      <div class=\"section-tag\">What We Offer</div>\n      <h2 class=\"section-title\">Everything your business needs online</h2>\n      <p class=\"section-sub\">We handle the whole thing \u2014 design, build, and launch \u2014 so you can focus on running your business.</p>\n    </div>\n    <div class=\"services-grid\">\n      <div class=\"service-card reveal reveal-delay-1\">\n        <div class=\"service-icon\"><i class=\"fa-solid fa-palette\"></i></div>\n        <h3>Custom Design</h3>\n        <p>No templates. Every site is built to match your brand, your audience, and your goals \u2014 from scratch.</p>\n      </div>\n      <div class=\"service-card reveal reveal-delay-2\">\n        <div class=\"service-icon\"><i class=\"fa-solid fa-mobile-screen\"></i></div>\n        <h3>Mobile-First</h3>\n        <p>Every site looks and works perfectly on phones, tablets, and desktops. No compromises.</p>\n      </div>\n      <div class=\"service-card reveal reveal-delay-3\">\n        <div class=\"service-icon\"><i class=\"fa-solid fa-rocket\"></i></div>\n        <h3>Fast & Optimized</h3>\n        <p>Fast-loading pages that rank higher on Google and keep visitors from bouncing before they even read a word.</p>\n      </div>\n      <div class=\"service-card reveal reveal-delay-1\">\n        <div class=\"service-icon\"><i class=\"fa-solid fa-magnifying-glass\"></i></div>\n        <h3>SEO Ready</h3>\n        <p>Built with search engines in mind from day one, so new customers can actually find you on Google.</p>\n      </div>\n      <div class=\"service-card reveal reveal-delay-2\">\n        <div class=\"service-icon\"><i class=\"fa-solid fa-pen-to-square\"></i></div>\n        <h3>Easy to Edit</h3>\n        <p>We set you up with a simple CMS so you can update your own content anytime, no tech knowledge needed.</p>\n      </div>\n      <div class=\"service-card reveal reveal-delay-3\">\n        <div class=\"service-icon\"><i class=\"fa-solid fa-screwdriver-wrench\"></i></div>\n        <h3>Ongoing Support</h3>\n        <p>We don't disappear after launch. We're here for updates, fixes, and any changes you need down the road.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n\n<!-- PROCESS -->\n<section class=\"process-section\" id=\"process\">\n  <div class=\"section-inner\">\n    <div class=\"section-header reveal\">\n      <div class=\"section-tag\">How It Works</div>\n      <h2 class=\"section-title\">You see your website before you pay a cent</h2>\n      <p class=\"section-sub\">Most web designers take your money then show you something. We do it the other way around.</p>\n    </div>\n    <div class=\"process-steps\" id=\"processSteps\">\n      <div class=\"process-line\"><div class=\"process-line-fill\" id=\"processLine\"></div></div>\n      <div class=\"step active reveal reveal-delay-1\">\n        <div class=\"step-num\">1</div>\n        <h3>You reach out</h3>\n        <p>Send us a quick message about your business. No forms, no commitment \u2014 just a conversation.</p>\n      </div>\n      <div class=\"step active reveal reveal-delay-2\">\n        <div class=\"step-num\">2</div>\n        <h3>We build a preview</h3>\n        <p>Before any call, we put together a real working preview of your site based on your business.</p>\n      </div>\n      <div class=\"step active reveal reveal-delay-3\">\n        <div class=\"step-num\">3</div>\n        <h3>We walk through it together</h3>\n        <p>We schedule a short call where you see exactly what your site would look like. No guesswork.</p>\n      </div>\n      <div class=\"step active reveal reveal-delay-4\">\n        <div class=\"step-num\">4</div>\n        <h3>You decide <i class=\"fa-solid fa-rocket\" style=\"color:var(--accent);font-size:0.9em\"></i></h3>\n        <p>If you love it, we finalize and launch. If not, no hard feelings \u2014 zero pressure, ever.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- WHY THIS WORKS -->\n<section style=\"background:var(--black);padding:5rem 5%\">\n  <div class=\"section-inner\">\n    <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:4rem;align-items:center\">\n      <div class=\"reveal from-left\">\n        <div class=\"section-tag\" style=\"color:#a5b4fc\">Our Approach</div>\n        <h2 class=\"section-title\" style=\"color:white\">Why we show before we charge</h2>\n        <p style=\"color:#71717a;font-size:1rem;line-height:1.75;margin-top:0.5rem\">Most businesses have been burned before \u2014 paid for a website that didn't deliver. We built our process around eliminating that risk entirely.</p>\n        <p style=\"color:#71717a;font-size:1rem;line-height:1.75;margin-top:1rem\">You get to see your actual site \u2014 built around your brand, your services, your city \u2014 before anything is agreed to. The price conversation only happens once you're already impressed.</p>\n        <a href=\"contact.html\" class=\"btn-primary\" style=\"margin-top:1.75rem;display:inline-flex\">Get your free preview <i class=\"fa-solid fa-arrow-right\"></i></a>\n      </div>\n      <div class=\"reveal from-right\" style=\"display:flex;flex-direction:column;gap:1rem\">\n        <div style=\"background:#111116;border:1px solid #27272a;border-radius:12px;padding:1.25rem;display:flex;gap:1rem;align-items:flex-start\">\n          <div style=\"width:40px;height:40px;background:#18181b;border-radius:10px;display:flex;align-items:center;justify-content:center;color:#a5b4fc;font-size:1rem;flex-shrink:0;border:1px solid #27272a\"><i class=\"fa-solid fa-eye\"></i></div>\n          <div><div style=\"color:white;font-weight:600;font-size:0.9rem;margin-bottom:0.3rem\">See it before you sign anything</div><div style=\"color:#71717a;font-size:0.85rem;line-height:1.6\">Your preview is a fully working website \u2014 not a mockup or a PDF. You click through it, see how it looks on your phone, and decide from there.</div></div>\n        </div>\n        <div style=\"background:#111116;border:1px solid #27272a;border-radius:12px;padding:1.25rem;display:flex;gap:1rem;align-items:flex-start\">\n          <div style=\"width:40px;height:40px;background:#18181b;border-radius:10px;display:flex;align-items:center;justify-content:center;color:#a5b4fc;font-size:1rem;flex-shrink:0;border:1px solid #27272a\"><i class=\"fa-solid fa-tag\"></i></div>\n          <div><div style=\"color:white;font-weight:600;font-size:0.9rem;margin-bottom:0.3rem\">Pricing based on your project</div><div style=\"color:#71717a;font-size:0.85rem;line-height:1.6\">Every business is different. After the preview call we'll give you a clear, flat-rate quote with no hourly billing or hidden fees.</div></div>\n        </div>\n        <div style=\"background:#111116;border:1px solid #27272a;border-radius:12px;padding:1.25rem;display:flex;gap:1rem;align-items:flex-start\">\n          <div style=\"width:40px;height:40px;background:#18181b;border-radius:10px;display:flex;align-items:center;justify-content:center;color:#a5b4fc;font-size:1rem;flex-shrink:0;border:1px solid #27272a\"><i class=\"fa-solid fa-shield-halved\"></i></div>\n          <div><div style=\"color:white;font-weight:600;font-size:0.9rem;margin-bottom:0.3rem\">Zero risk, zero pressure</div><div style=\"color:#71717a;font-size:0.85rem;line-height:1.6\">If you don't move forward, you keep the preview and owe us nothing. We'd rather earn your trust than your deposit.</div></div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- TESTIMONIALS -->\n<section class=\"testimonials\" id=\"testimonials\">\n  <div class=\"section-inner\">\n    <div class=\"section-header reveal\">\n      <div class=\"section-tag\">Testimonials</div>\n      <h2 class=\"section-title\">Small businesses love working with us</h2>\n    </div>\n    <div class=\"testimonials-grid\">\n      <div class=\"testimonial reveal reveal-delay-1\">\n        <div class=\"stars\"><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i></div>\n        <blockquote>\"We went from zero online presence to getting 5\u201310 new inquiries a week. LumaDesign completely changed our business.\"</blockquote>\n        <div class=\"testimonial-author\">\n          <div class=\"avatar\">MR</div>\n          <div><div class=\"author-name\">Maria R.</div><div class=\"author-biz\">Rosa's Artisan Bakery</div></div>\n        </div>\n      </div>\n      <div class=\"testimonial reveal reveal-delay-2\">\n        <div class=\"stars\"><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i></div>\n        <blockquote>\"Our old website was embarrassing to share. The new one looks incredible and we've already seen a huge difference in customer trust.\"</blockquote>\n        <div class=\"testimonial-author\">\n          <div class=\"avatar\">JT</div>\n          <div><div class=\"author-name\">James T.</div><div class=\"author-biz\">T&T Plumbing Co.</div></div>\n        </div>\n      </div>\n      <div class=\"testimonial reveal reveal-delay-3\">\n        <div class=\"stars\"><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i><i class=\"fa-solid fa-star\"></i></div>\n        <blockquote>\"Super professional, fast turnaround, and they actually listened to what I wanted. Couldn't be happier with how it turned out.\"</blockquote>\n        <div class=\"testimonial-author\">\n          <div class=\"avatar\">SL</div>\n          <div><div class=\"author-name\">Sofia L.</div><div class=\"author-biz\">Luz Yoga Studio</div></div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- FAQ -->\n<section class=\"faq-section\" id=\"faq\">\n  <div class=\"section-inner\">\n    <div class=\"section-header reveal\">\n      <div class=\"section-tag\">FAQ</div>\n      <h2 class=\"section-title\">Common questions</h2>\n      <p class=\"section-sub\">Everything you need to know before getting started.</p>\n    </div>\n    <div class=\"faq-grid reveal\">\n      <div class=\"faq-item\" onclick=\"toggleFaq(this)\">\n        <div class=\"faq-q\">How long does it take to build a website? <i class=\"fa-solid fa-plus faq-icon\"></i></div>\n        <div class=\"faq-a\">Most projects are complete within 5\u201310 business days. The Starter plan typically takes 3\u20135 days, Business takes 5\u20137 days, and Premium can take up to 10 days depending on scope.</div>\n      </div>\n      <div class=\"faq-item\" onclick=\"toggleFaq(this)\">\n        <div class=\"faq-q\">Do I need to provide content and images? <i class=\"fa-solid fa-plus faq-icon\"></i></div>\n        <div class=\"faq-a\">You'll need to provide the text and any photos of your business. If you don't have photos, we can source high-quality stock imagery that fits your brand at no extra charge.</div>\n      </div>\n      <div class=\"faq-item\" onclick=\"toggleFaq(this)\">\n        <div class=\"faq-q\">Will I be able to edit the site myself after launch? <i class=\"fa-solid fa-plus faq-icon\"></i></div>\n        <div class=\"faq-a\">Yes! All our sites are set up with a simple content management system. You can update text, images, hours, and more without any technical knowledge. We walk you through it after launch.</div>\n      </div>\n      <div class=\"faq-item\" onclick=\"toggleFaq(this)\">\n        <div class=\"faq-q\">What if I don't like the initial design? <i class=\"fa-solid fa-plus faq-icon\"></i></div>\n        <div class=\"faq-a\">No worries \u2014 that's what revision rounds are for. We work with you until you love it. Our goal is a site you're proud to share, and we won't stop until we get there.</div>\n      </div>\n      <div class=\"faq-item\" onclick=\"toggleFaq(this)\">\n        <div class=\"faq-q\">Does the price include hosting? <i class=\"fa-solid fa-plus faq-icon\"></i></div>\n        <div class=\"faq-a\">Your quote covers design and development. Hosting and domain are separate \u2014 we'll recommend the best options for your budget and walk you through the whole setup.</div>\n      </div>\n      <div class=\"faq-item\" onclick=\"toggleFaq(this)\">\n        <div class=\"faq-q\">What happens after my support period ends? <i class=\"fa-solid fa-plus faq-icon\"></i></div>\n        <div class=\"faq-a\">You can continue with a monthly maintenance plan, or reach out on a project-by-project basis for updates and changes. We're always available \u2014 the support period just means priority response time.</div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- CTA -->\n<section class=\"cta-section\">\n  <div class=\"cta-inner reveal\">\n    <h2>See your new website before you pay anything</h2>\n    <p>Send us a message, and we'll build you a real working preview of your site \u2014 completely free, no strings attached.</p>\n    <a href=\"contact.html\" class=\"btn-white\">Get My Free Preview <i class=\"fa-solid fa-arrow-right\"></i></a>\n  </div>\n</section>\n\n\n<!-- FOOTER -->\n<footer>\n  <div class=\"footer-top\">\n    <div>\n      <div class=\"footer-logo\">luma<span>design</span></div>\n      <p class=\"footer-desc\">Custom websites for small businesses that want to look professional, get found on Google, and actually convert visitors into customers.</p>\n    </div>\n    <div class=\"footer-col\">\n      <h4>Services</h4>\n      <ul>\n        <li><a href=\"#services\">Custom Design</a></li>\n        <li><a href=\"#services\">Mobile-First</a></li>\n        <li><a href=\"#services\">SEO Optimization</a></li>\n        <li><a href=\"#services\">E-commerce</a></li>\n        <li><a href=\"#services\">Ongoing Support</a></li>\n      </ul>\n    </div>\n    <div class=\"footer-col\">\n      <h4>Company</h4>\n      <ul>\n        <li><a href=\"#process\">How It Works</a></li>\n        <li><a href=\"#faq\">FAQ</a></li>\n        <li><a href=\"contact.html\">Contact</a></li>\n      </ul>\n    </div>\n    <div class=\"footer-col\">\n      <h4>Get Started</h4>\n      <ul>\n        <li><a href=\"contact.html\">Get Your Free Preview</a></li>\n        <li><a href=\"#process\">How It Works</a></li>\n        <li><a href=\"#faq\">FAQ</a></li>\n      </ul>\n    </div>\n  </div>\n  <div class=\"footer-bottom\">\n    <p>\u00a9 2026 LumaDesign. All rights reserved.</p>\n    <div style=\"display:flex;gap:1.5rem\">\n      <a href=\"#\">Privacy Policy</a>\n      <a href=\"#\">Terms of Service</a>\n    </div>\n  </div>\n</footer>\n\n<!-- BACK TO TOP -->\n<button class=\"back-top\" id=\"backTop\" onclick=\"window.scrollTo({top:0,behavior:'smooth'})\" aria-label=\"Back to top\">\n  <i class=\"fa-solid fa-arrow-up\"></i>\n</button>\n\n<script>\n  // \u2500\u2500 Nav scroll effect\n  const nav = document.getElementById('mainNav');\n  window.addEventListener('scroll', () => {\n    nav.classList.toggle('scrolled', window.scrollY > 40);\n    document.getElementById('backTop').classList.toggle('visible', window.scrollY > 400);\n  });\n\n  // \u2500\u2500 Mobile menu\n  function toggleMobile() {\n    const menu = document.getElementById('mobileMenu');\n    const burger = document.getElementById('hamburger');\n    menu.classList.toggle('open');\n    burger.classList.toggle('open');\n  }\n  function closeMobile() {\n    document.getElementById('mobileMenu').classList.remove('open');\n    document.getElementById('hamburger').classList.remove('open');\n  }\n\n  // \u2500\u2500 Scroll reveal + special hooks\n  const observer = new IntersectionObserver((entries) => {\n    entries.forEach(entry => {\n      if (!entry.isIntersecting) return;\n      const el = entry.target;\n      el.classList.add('visible');\n\n      // Animate process line\n      if (el.id === 'processSteps') {\n        setTimeout(() => document.getElementById('processLine').classList.add('animate'), 200);\n      }\n\n      // Counter animation for proof strip numbers\n      if (el.classList.contains('count-up')) {\n        animateCounter(el);\n        observer.unobserve(el);\n      }\n    });\n  }, { threshold: 0.15 });\n\n  document.querySelectorAll('.reveal').forEach(el => observer.observe(el));\n  document.querySelectorAll('.count-up').forEach(el => observer.observe(el));\n  const stepsEl = document.getElementById('processSteps');\n  if (stepsEl) observer.observe(stepsEl);\n\n  // \u2500\u2500 Counter animation\n  function animateCounter(el) {\n    const target = parseFloat(el.dataset.target);\n    const suffix = el.dataset.suffix || '';\n    const prefix = el.dataset.prefix || '';\n    const decimals = el.dataset.decimals ? parseInt(el.dataset.decimals) : 0;\n    const duration = 1400;\n    const start = performance.now();\n    function step(now) {\n      const progress = Math.min((now - start) / duration, 1);\n      const eased = 1 - Math.pow(1 - progress, 3); // ease out cubic\n      const value = eased * target;\n      el.textContent = prefix + value.toFixed(decimals) + suffix;\n      if (progress < 1) requestAnimationFrame(step);\n    }\n    requestAnimationFrame(step);\n  }\n\n  // \u2500\u2500 Problem card mouse-spotlight\n  document.querySelectorAll('.problem-card').forEach(card => {\n    card.addEventListener('mousemove', e => {\n      const rect = card.getBoundingClientRect();\n      card.style.setProperty('--mx', (e.clientX - rect.left) + 'px');\n      card.style.setProperty('--my', (e.clientY - rect.top) + 'px');\n    });\n  });\n\n  // \u2500\u2500 FAQ\n  function toggleFaq(el) {\n    const wasOpen = el.classList.contains('open');\n    document.querySelectorAll('.faq-item').forEach(i => i.classList.remove('open'));\n    if (!wasOpen) el.classList.add('open');\n  }\n\n  // \u2500\u2500 Contact form\n  function handleSubmit(e) {\n    e.preventDefault();\n    const btn = e.target.querySelector('.form-submit');\n    btn.innerHTML = '<i class=\"fa-solid fa-check\"></i> Message Sent!';\n    btn.style.background = '#16a34a';\n    btn.style.boxShadow = '0 4px 14px rgba(22,163,74,0.3)';\n    setTimeout(() => {\n      btn.innerHTML = 'Send Message <i class=\"fa-solid fa-paper-plane\"></i>';\n      btn.style.background = '';\n      btn.style.boxShadow = '';\n      e.target.reset();\n    }, 3500);\n  }\n\n  // \u2500\u2500 Smooth nav scroll offset\n  document.querySelectorAll('a[href^=\"#\"]').forEach(a => {\n    a.addEventListener('click', e => {\n      const target = document.querySelector(a.getAttribute('href'));\n      if (target) {\n        e.preventDefault();\n        window.scrollTo({ top: target.getBoundingClientRect().top + window.scrollY - 80, behavior: 'smooth' });\n      }\n    });\n  });\n\n  // \u2500\u2500 Staggered reveal for service cards and testimonials (for icon/star anims)\n  document.querySelectorAll('.service-card, .testimonial').forEach(el => observer.observe(el));\n</script>\n</body>\n</html>\n";
const CONTACT_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\"/>\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"/>\n  <title>Get Your Free Preview \u2014 LumaDesign</title>\n  <link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap\" rel=\"stylesheet\"/>\n  <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css\"/>\n  <style>\n    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n    :root {\n      --black: #09090b;\n      --white: #ffffff;\n      --gray-50: #fafafa;\n      --gray-100: #f4f4f5;\n      --gray-200: #e4e4e7;\n      --gray-400: #a1a1aa;\n      --gray-500: #71717a;\n      --gray-700: #3f3f46;\n      --accent: #6366f1;\n      --accent-light: #eef2ff;\n      --accent-dark: #4f46e5;\n      --accent-glow: rgba(99,102,241,0.25);\n      --radius: 14px;\n    }\n\n    html { scroll-behavior: smooth; }\n    body {\n      font-family: 'Inter', sans-serif;\n      color: var(--black);\n      background: var(--white);\n      line-height: 1.6;\n      min-height: 100vh;\n    }\n\n    /* \u2500\u2500 NAV \u2500\u2500 */\n    nav {\n      position: fixed; top: 0; left: 0; right: 0; z-index: 200;\n      display: flex; align-items: center; justify-content: space-between;\n      padding: 1rem 5%;\n      background: rgba(255,255,255,0.92);\n      backdrop-filter: blur(16px);\n      box-shadow: 0 1px 0 var(--gray-200);\n    }\n    .logo {\n      font-size: 1.4rem; font-weight: 800; letter-spacing: -0.5px;\n      color: var(--black); text-decoration: none; display: flex; align-items: center; gap: 0.4rem;\n    }\n    .logo-dot { width: 8px; height: 8px; background: var(--accent); border-radius: 50%; }\n    .logo span { color: var(--accent); }\n    .nav-back {\n      display: inline-flex; align-items: center; gap: 0.5rem;\n      font-size: 0.875rem; font-weight: 500; color: var(--gray-500);\n      text-decoration: none; transition: color 0.2s;\n    }\n    .nav-back:hover { color: var(--accent); }\n\n    /* \u2500\u2500 ENTRANCE ANIMATIONS \u2500\u2500 */\n    @keyframes fadeUp {\n      from { opacity: 0; transform: translateY(22px); }\n      to   { opacity: 1; transform: translateY(0); }\n    }\n    @keyframes fadeLeft {\n      from { opacity: 0; transform: translateX(-28px); }\n      to   { opacity: 1; transform: translateX(0); }\n    }\n    @keyframes fadeRight {\n      from { opacity: 0; transform: translateX(28px); }\n      to   { opacity: 1; transform: translateX(0); }\n    }\n    @keyframes scaleIn {\n      from { opacity: 0; transform: scale(0.88); }\n      to   { opacity: 1; transform: scale(1); }\n    }\n\n    /* left panel elements */\n    .left-tag    { opacity: 0; animation: fadeLeft 0.55s cubic-bezier(.16,1,.3,1) 0.05s forwards; }\n    .left-panel h1 { opacity: 0; animation: fadeLeft 0.6s cubic-bezier(.16,1,.3,1) 0.15s forwards; }\n    .left-panel > .left-inner > p { opacity: 0; animation: fadeLeft 0.6s cubic-bezier(.16,1,.3,1) 0.25s forwards; }\n\n    .step-item:nth-child(1) { opacity: 0; animation: fadeLeft 0.55s cubic-bezier(.16,1,.3,1) 0.32s forwards; }\n    .step-item:nth-child(2) { opacity: 0; animation: fadeLeft 0.55s cubic-bezier(.16,1,.3,1) 0.42s forwards; }\n    .step-item:nth-child(3) { opacity: 0; animation: fadeLeft 0.55s cubic-bezier(.16,1,.3,1) 0.52s forwards; }\n\n    /* right panel \u2014 form slides in from right */\n    .form-card { opacity: 0; animation: fadeRight 0.7s cubic-bezier(.16,1,.3,1) 0.2s forwards; }\n\n    /* divider line between panels */\n    .left-contact { opacity: 0; animation: fadeUp 0.5s ease 0.65s forwards; }\n\n    /* \u2500\u2500 PAGE LAYOUT \u2500\u2500 */\n    .page-wrap {\n      height: 100vh;\n      display: grid;\n      grid-template-columns: 1fr 1.2fr;\n      overflow: hidden;\n    }\n\n    /* LEFT PANEL */\n    .left-panel {\n      background: var(--black);\n      padding: 5rem 5% 2rem 5%;\n      display: flex; flex-direction: column; justify-content: center;\n      position: relative; overflow: hidden;\n    }\n    .left-panel::before {\n      content: '';\n      position: absolute; inset: 0;\n      background:\n        radial-gradient(ellipse 600px 400px at 20% 30%, rgba(99,102,241,0.12) 0%, transparent 70%),\n        radial-gradient(ellipse 400px 300px at 80% 80%, rgba(99,102,241,0.07) 0%, transparent 70%);\n      pointer-events: none;\n    }\n    .left-inner { position: relative; z-index: 1; max-width: 440px; }\n\n    .left-tag {\n      display: inline-flex; align-items: center; gap: 0.4rem;\n      font-size: 0.7rem; font-weight: 700; text-transform: uppercase;\n      letter-spacing: 0.1em; color: #a5b4fc; margin-bottom: 0.75rem;\n    }\n    .left-tag::before { content: ''; width: 16px; height: 2px; background: #a5b4fc; border-radius: 1px; }\n\n    .left-panel h1 {\n      font-size: clamp(1.6rem, 2.2vw, 2.2rem);\n      font-weight: 800; line-height: 1.15; letter-spacing: -1px;\n      color: var(--white); margin-bottom: 0.6rem;\n    }\n    .gradient-text {\n      background: linear-gradient(135deg, var(--accent) 0%, #818cf8 100%);\n      -webkit-background-clip: text; -webkit-text-fill-color: transparent;\n      background-clip: text;\n    }\n    .left-panel p {\n      color: #71717a; font-size: 0.875rem; line-height: 1.65; margin-bottom: 1.5rem;\n    }\n\n    .steps-list { display: flex; flex-direction: column; gap: 0.6rem; }\n    .step-item { display: flex; align-items: center; gap: 0.75rem; }\n    .step-circle {\n      width: 26px; height: 26px; border-radius: 50%;\n      background: #18181b; border: 1px solid #27272a;\n      display: flex; align-items: center; justify-content: center;\n      font-size: 0.68rem; font-weight: 700; color: #a5b4fc;\n      flex-shrink: 0;\n    }\n    .step-item span { font-size: 0.85rem; font-weight: 500; color: #a1a1aa; }\n\n    .left-contact {\n      margin-top: 2rem; padding-top: 1.5rem; border-top: 1px solid #27272a;\n      display: flex; align-items: center; gap: 0.6rem;\n    }\n    .lc-icon { width: 28px; height: 28px; background: #18181b; border: 1px solid #27272a; border-radius: 7px; display: flex; align-items: center; justify-content: center; color: #a5b4fc; font-size: 0.7rem; flex-shrink: 0; }\n    .lc-value { font-size: 0.875rem; font-weight: 500; color: #a1a1aa; }\n\n    /* RIGHT PANEL */\n    .right-panel {\n      background: var(--gray-50);\n      padding: 5rem 5% 2rem;\n      display: flex; align-items: center; justify-content: center;\n      overflow-y: auto;\n    }\n    .form-wrap { width: 100%; max-width: 500px; }\n\n    .form-card {\n      background: var(--white);\n      border: 1px solid var(--gray-200);\n      border-radius: 18px;\n      padding: 2rem;\n      box-shadow: 0 8px 32px rgba(0,0,0,0.06);\n    }\n\n    .form-header { margin-bottom: 1.25rem; }\n    .form-header h2 { font-size: 1.25rem; font-weight: 700; margin-bottom: 0.25rem; }\n    .form-header p { font-size: 0.82rem; color: var(--gray-500); }\n\n    form { display: flex; flex-direction: column; gap: 0.75rem; }\n    .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 0.75rem; }\n    .form-group { display: flex; flex-direction: column; gap: 0.25rem; }\n    label { font-size: 0.74rem; font-weight: 600; color: var(--gray-700); }\n    input, textarea, select {\n      width: 100%; padding: 0.6rem 0.85rem;\n      border: 1.5px solid var(--gray-200); border-radius: 8px;\n      font-family: inherit; font-size: 0.85rem; color: var(--black);\n      background: var(--white); outline: none;\n      transition: border-color 0.2s, box-shadow 0.2s;\n    }\n    input:focus, textarea:focus, select:focus {\n      border-color: var(--accent);\n      box-shadow: 0 0 0 3px rgba(99,102,241,0.12);\n    }\n    textarea { resize: vertical; min-height: 80px; }\n\n    .form-submit {\n      background: var(--accent); color: var(--white); border: none;\n      padding: 0.75rem; border-radius: 9px; font-family: inherit;\n      font-size: 0.9rem; font-weight: 600; cursor: pointer;\n      transition: background 0.2s, transform 0.15s, box-shadow 0.2s;\n      box-shadow: 0 4px 14px var(--accent-glow);\n      display: flex; align-items: center; justify-content: center; gap: 0.5rem;\n      margin-top: 0.25rem;\n    }\n    .form-submit:hover { background: var(--accent-dark); transform: translateY(-1px); box-shadow: 0 8px 24px var(--accent-glow); }\n\n    .form-note { font-size: 0.775rem; color: var(--gray-400); text-align: center; margin-top: 0.5rem; }\n\n    /* \u2500\u2500 SUCCESS STATE \u2500\u2500 */\n    .success-state {\n      display: none; text-align: center; padding: 2rem 0;\n    }\n    .success-icon {\n      width: 64px; height: 64px; background: #dcfce7; border-radius: 50%;\n      display: flex; align-items: center; justify-content: center;\n      margin: 0 auto 1.25rem;\n      font-size: 1.5rem; color: #16a34a;\n      animation: popIn 0.4s cubic-bezier(.34,1.56,.64,1);\n    }\n    @keyframes popIn { from { transform: scale(0); } to { transform: scale(1); } }\n    .success-state h3 { font-size: 1.2rem; font-weight: 700; margin-bottom: 0.5rem; }\n    .success-state p { font-size: 0.9rem; color: var(--gray-500); line-height: 1.6; }\n    .success-back { display: inline-flex; align-items: center; gap: 0.4rem; margin-top: 1.5rem; font-size: 0.875rem; font-weight: 600; color: var(--accent); text-decoration: none; }\n    .success-back:hover { text-decoration: underline; }\n\n    /* \u2500\u2500 RESPONSIVE \u2500\u2500 */\n    @media (max-width: 900px) {\n      .page-wrap { grid-template-columns: 1fr; height: auto; overflow: visible; }\n      .left-panel { padding: 6rem 5% 3rem; }\n      .left-inner { max-width: 100%; }\n      .right-panel { padding: 3rem 5% 4rem; overflow-y: visible; }\n    }\n    @media (max-width: 520px) {\n      .form-card { padding: 1.5rem; }\n      .form-row { grid-template-columns: 1fr; }\n      .left-panel h1 { font-size: 1.7rem; }\n      .left-contact { grid-template-columns: 1fr; }\n    }\n  </style>\n</head>\n<body>\n\n<!-- NAV -->\n<nav>\n  <a href=\"index.html\" class=\"logo\"><div class=\"logo-dot\"></div>luma<span>design</span></a>\n  <a href=\"index.html\" class=\"nav-back\"><i class=\"fa-solid fa-arrow-left\"></i> Back to home</a>\n</nav>\n\n<!-- PAGE -->\n<div class=\"page-wrap\">\n\n  <!-- LEFT -->\n  <div class=\"left-panel\">\n    <div class=\"left-inner\">\n      <div class=\"left-tag\">Free Preview</div>\n      <h1>See your website<br><span class=\"gradient-text\">before you pay</span></h1>\n      <p>Fill in the form and we'll build a real working preview of your site \u2014 completely free. Then we'll hop on a call so you can see it live and decide from there.</p>\n\n      <div class=\"steps-list\">\n        <div class=\"step-item\">\n          <div class=\"step-circle\">1</div>\n          <span>Fill in the form</span>\n        </div>\n        <div class=\"step-item\">\n          <div class=\"step-circle\">2</div>\n          <span>We build your free preview</span>\n        </div>\n        <div class=\"step-item\">\n          <div class=\"step-circle\">3</div>\n          <span>We walk through it on a call</span>\n        </div>\n      </div>\n\n      <div class=\"left-contact\">\n        <div class=\"lc-icon\"><i class=\"fa-solid fa-envelope\"></i></div>\n        <div class=\"lc-value\">info@lumadesign.ca</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- RIGHT -->\n  <div class=\"right-panel\">\n    <div class=\"form-wrap\">\n      <div class=\"form-card\">\n\n        <div id=\"formContent\">\n          <div class=\"form-header\">\n            <h2>Get your free preview</h2>\n            <p>Takes 2 minutes \u2014 we'll take it from there.</p>\n          </div>\n          <form id=\"contactForm\" onsubmit=\"handleSubmit(event)\">\n            <input type=\"hidden\" name=\"access_key\" value=\"5c517894-32e9-49a5-844e-ae4bde56f5b9\"/>\n            <input type=\"hidden\" name=\"subject\" value=\"New Website Preview Request \u2014 LumaDesign\"/>\n            <input type=\"hidden\" name=\"from_name\" value=\"LumaDesign Contact Form\"/>\n            <input type=\"hidden\" name=\"redirect\" value=\"false\"/>\n            <div class=\"form-row\">\n              <div class=\"form-group\">\n                <label>Your name</label>\n                <input type=\"text\" name=\"name\" placeholder=\"Jane Smith\" required/>\n              </div>\n              <div class=\"form-group\">\n                <label>Email address</label>\n                <input type=\"email\" name=\"email\" placeholder=\"jane@yourbiz.com\" required/>\n              </div>\n            </div>\n            <div class=\"form-group\">\n              <label>Business name</label>\n              <input type=\"text\" name=\"business_name\" placeholder=\"Your Business Name\"/>\n            </div>\n            <div class=\"form-group\">\n              <label>Phone number <span style=\"color:var(--gray-400);font-weight:400\">(optional)</span></label>\n              <input type=\"tel\" name=\"phone\" placeholder=\"(604) 000-0000\"/>\n            </div>\n            <div class=\"form-group\">\n              <label>What do you need?</label>\n              <select name=\"project_type\">\n                <option value=\"\" disabled selected>Choose one\u2026</option>\n                <option>Brand new website \u2014 I have nothing right now</option>\n                <option>Redesign \u2014 my current site is outdated</option>\n                <option>E-commerce store</option>\n                <option>Something else</option>\n              </select>\n            </div>\n            <div class=\"form-group\">\n              <label>Tell us about your business</label>\n              <textarea name=\"message\" placeholder=\"What do you do? Who are your customers? What city are you in? The more detail, the better your preview will be.\"></textarea>\n            </div>\n            <button type=\"submit\" class=\"form-submit\" id=\"submitBtn\">\n              Request My Free Preview <i class=\"fa-solid fa-paper-plane\"></i>\n            </button>\n            <p class=\"form-note\"><i class=\"fa-solid fa-lock\" style=\"font-size:0.7rem\"></i> No payment info required. We'll never spam you.</p>\n          </form>\n        </div>\n\n        <div class=\"success-state\" id=\"successState\">\n          <div class=\"success-icon\"><i class=\"fa-solid fa-check\"></i></div>\n          <h3>You're all set!</h3>\n          <p>We got your message and we'll start working on your preview right away. Expect to hear from us within 24 hours to schedule your walkthrough call.</p>\n          <a href=\"index.html\" class=\"success-back\"><i class=\"fa-solid fa-arrow-left\"></i> Back to home</a>\n        </div>\n\n      </div>\n    </div>\n  </div>\n\n</div>\n\n<script>\n  async function handleSubmit(e) {\n    e.preventDefault();\n    const btn = document.getElementById('submitBtn');\n    btn.disabled = true;\n    btn.innerHTML = '<i class=\"fa-solid fa-spinner fa-spin\"></i> Sending\u2026';\n\n    const formData = new FormData(document.getElementById('contactForm'));\n    const data = Object.fromEntries(formData);\n\n    try {\n      const res = await fetch('https://api.web3forms.com/submit', {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },\n        body: JSON.stringify(data)\n      });\n      const json = await res.json();\n      if (json.success) {\n        document.getElementById('formContent').style.display = 'none';\n        document.getElementById('successState').style.display = 'block';\n      } else {\n        btn.disabled = false;\n        btn.innerHTML = 'Request My Free Preview <i class=\"fa-solid fa-paper-plane\"></i>';\n        alert('Something went wrong. Please try again or email us directly at info@lumadesign.ca');\n      }\n    } catch {\n      btn.disabled = false;\n      btn.innerHTML = 'Request My Free Preview <i class=\"fa-solid fa-paper-plane\"></i>';\n      alert('Something went wrong. Please try again or email us directly at info@lumadesign.ca');\n    }\n  }\n</script>\n</body>\n</html>\n";

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/' || path === '/index.html') {
      return new Response(INDEX_HTML, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
    }
    if (path === '/contact' || path === '/contact.html') {
      return new Response(CONTACT_HTML, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
    }
    return new Response('Not found', { status: 404 });
  }
};
